"""Gated live-bet submission and settlement for Forecasts."""

from __future__ import annotations

import asyncio
import os
import time
from datetime import UTC, datetime
from decimal import ROUND_DOWN, ROUND_HALF_UP, Decimal, InvalidOperation
from typing import Any, Literal

from noosphere.forecasts._kalshi_live_client import KalshiLiveClient, KalshiLiveOrder
from noosphere.forecasts._polymarket_live_client import (
    PolymarketLiveClient,
    PolymarketLiveOrder,
)
from noosphere.forecasts.safety import (
    check_all_gates,
    gate_context_from_env,
    maybe_engage_daily_loss_kill_switch,
    record_exchange_error,
    reset_exchange_error_streak,
)
from noosphere.models import (
    ForecastBet,
    ForecastBetMode,
    ForecastBetSide,
    ForecastBetStatus,
    ForecastExchange,
    ForecastMarket,
    ForecastOutcome,
    ForecastPortfolioState,
    ForecastPrediction,
)
from noosphere.observability import get_logger

log = get_logger(__name__)
MONEY = Decimal("0.01")
PRICE = Decimal("0.000001")


async def submit_live_bet(
    store: Any,
    bet_id: str,
    *,
    polymarket_client: Any = None,
    kalshi_client: Any = None,
    operator_id: str,
) -> ForecastBet:
    """
    Gate and submit one live bet. This function never submits unless
    check_all_gates has passed and operator_id is non-empty.
    """

    if not operator_id or not operator_id.strip():
        raise ValueError("operator_id is required for live bet submission")

    bet, prediction, market, portfolio = _load_submission_context(store, bet_id)
    ctx = gate_context_from_env(portfolio)
    check_all_gates(prediction=prediction, bet=bet, ctx=ctx)

    try:
        if _enum_value(bet.exchange) == ForecastExchange.POLYMARKET.value:
            client = polymarket_client or PolymarketLiveClient.from_env()
            order = await _submit_polymarket_order(client, bet, market)
        elif _enum_value(bet.exchange) == ForecastExchange.KALSHI.value:
            client = kalshi_client or KalshiLiveClient.from_env()
            order = await _submit_kalshi_order(client, bet, market)
        else:
            raise ValueError(f"unsupported live exchange: {bet.exchange!r}")

        submitted = _mark_submitted(
            store,
            bet.id,
            order,
            submitted_at=datetime.now(UTC),
        )
        terminal_order, terminal_status = await _poll_order_status(
            client,
            order,
            expected_fill=Decimal(submitted.stake_usd),
        )
        updated = _apply_order_status(
            store,
            submitted.id,
            terminal_order,
            terminal_status,
        )
        if updated.status == ForecastBetStatus.FILLED:
            reset_exchange_error_streak(updated.organization_id)
        return updated
    except Exception as exc:
        updated = _mark_failed(store, bet.id, exc)
        record_exchange_error(store, updated.organization_id)
        return updated


async def settle_live_bet_on_resolution(
    store: Any,
    bet_id: str,
    market_outcome: Literal["YES", "NO", "CANCELLED"],
) -> ForecastBet:
    """Mirror paper settlement and credit live balance with realized payoff."""

    outcome = ForecastOutcome(market_outcome)
    timestamp = datetime.now(UTC)
    with store.session() as session:
        bet = session.get(ForecastBet, bet_id)
        if bet is None:
            raise KeyError(f"unknown forecast bet: {bet_id}")
        if _enum_value(bet.mode) != ForecastBetMode.LIVE.value:
            raise ValueError("settle_live_bet_on_resolution only accepts LIVE bets")
        if _enum_value(bet.status) == ForecastBetStatus.SETTLED.value:
            return bet.model_copy()
        if _enum_value(bet.status) != ForecastBetStatus.FILLED.value:
            raise ValueError("only FILLED live bets can be settled")

        payoff, exit_price = _settlement_payoff(bet, outcome)
        pnl = _money(payoff - Decimal(bet.stake_usd))
        bet.status = ForecastBetStatus.SETTLED
        bet.exit_price = exit_price
        bet.settlement_pnl_usd = pnl
        bet.settled_at = timestamp

        state = _portfolio_state(session, bet.organization_id, now=timestamp)
        state.live_balance_usd = _money(Decimal(state.live_balance_usd or 0) + payoff)
        if pnl < Decimal("0"):
            state.daily_loss_usd = _money(Decimal(state.daily_loss_usd) + abs(pnl))
        state.updated_at = timestamp

        session.add(state)
        session.add(bet)
        session.commit()
        session.refresh(bet)
        result = bet.model_copy()

    maybe_engage_daily_loss_kill_switch(store, result.organization_id)
    return result


def _load_submission_context(
    store: Any,
    bet_id: str,
) -> tuple[
    ForecastBet,
    ForecastPrediction,
    ForecastMarket,
    ForecastPortfolioState | None,
]:
    with store.session() as session:
        bet = session.get(ForecastBet, bet_id)
        if bet is None:
            raise KeyError(f"unknown forecast bet: {bet_id}")
        if _enum_value(bet.mode) != ForecastBetMode.LIVE.value:
            raise ValueError("submit_live_bet only accepts LIVE bets")
        prediction = session.get(ForecastPrediction, bet.prediction_id)
        if prediction is None:
            raise KeyError(f"unknown forecast prediction: {bet.prediction_id}")
        market = session.get(ForecastMarket, prediction.market_id)
        if market is None:
            raise KeyError(f"unknown forecast market: {prediction.market_id}")
        state = _portfolio_state_or_none(session, bet.organization_id)
        return (
            bet.model_copy(),
            prediction.model_copy(),
            market.model_copy(),
            state.model_copy() if state is not None else None,
        )


async def _submit_polymarket_order(
    client: Any,
    bet: ForecastBet,
    market: ForecastMarket,
) -> PolymarketLiveOrder:
    side = ForecastBetSide(_enum_value(bet.side))
    token_id, outcome_index = _polymarket_token_id(market, side)
    price = _decimal(bet.entry_price)
    size = _money(_decimal(bet.stake_usd) / price)
    return await client.place_order(
        token_id,
        outcome_index,
        "BUY",
        size,
        price,
        os.getenv("FORECASTS_LIVE_ORDER_TYPE", "GTC"),
    )


async def _submit_kalshi_order(
    client: Any,
    bet: ForecastBet,
    market: ForecastMarket,
) -> KalshiLiveOrder:
    side = ForecastBetSide(_enum_value(bet.side))
    price = _decimal(bet.entry_price)
    count = max(
        1,
        int((_decimal(bet.stake_usd) / price).to_integral_value(rounding=ROUND_DOWN)),
    )
    return await client.place_order(
        market.external_id,
        side.value,
        count,
        price,
        os.getenv("FORECASTS_LIVE_ORDER_TYPE", "GTC"),
        bet.client_order_id or bet.id,
    )


async def _poll_order_status(
    client: Any,
    initial_order: Any,
    *,
    expected_fill: Decimal,
) -> tuple[Any, ForecastBetStatus]:
    order = initial_order
    status = _bet_status_from_order(order)
    if status in {
        ForecastBetStatus.FILLED,
        ForecastBetStatus.CANCELLED,
        ForecastBetStatus.FAILED,
    }:
        return order, status
    if _is_partial_fill(order, expected_fill):
        return order, ForecastBetStatus.SUBMITTED

    deadline = time.monotonic() + _poll_timeout_s()
    while time.monotonic() < deadline:
        order = await client.get_order(order.external_order_id)
        status = _bet_status_from_order(order)
        if status in {
            ForecastBetStatus.FILLED,
            ForecastBetStatus.CANCELLED,
            ForecastBetStatus.FAILED,
        }:
            return order, status
        if _is_partial_fill(order, expected_fill):
            return order, ForecastBetStatus.SUBMITTED
        await asyncio.sleep(min(1.0, max(0.0, deadline - time.monotonic())))
    return order, ForecastBetStatus.SUBMITTED


def _mark_submitted(
    store: Any,
    bet_id: str,
    order: Any,
    *,
    submitted_at: datetime,
) -> ForecastBet:
    with store.session() as session:
        bet = session.get(ForecastBet, bet_id)
        if bet is None:
            raise KeyError(f"unknown forecast bet: {bet_id}")
        bet.status = ForecastBetStatus.SUBMITTED
        bet.external_order_id = order.external_order_id
        bet.submitted_at = submitted_at
        session.add(bet)
        session.commit()
        session.refresh(bet)
        return bet.model_copy()


def _apply_order_status(
    store: Any,
    bet_id: str,
    order: Any,
    status: ForecastBetStatus,
) -> ForecastBet:
    timestamp = datetime.now(UTC)
    with store.session() as session:
        bet = session.get(ForecastBet, bet_id)
        if bet is None:
            raise KeyError(f"unknown forecast bet: {bet_id}")
        bet.external_order_id = order.external_order_id
        if status != ForecastBetStatus.SUBMITTED:
            bet.status = status
        if status == ForecastBetStatus.FILLED:
            state = _portfolio_state(session, bet.organization_id, now=timestamp)
            state.live_balance_usd = _money(
                Decimal(state.live_balance_usd or 0) - Decimal(bet.stake_usd)
            )
            state.updated_at = timestamp
            session.add(state)
        session.add(bet)
        session.commit()
        session.refresh(bet)
        return bet.model_copy()


def _mark_failed(store: Any, bet_id: str, exc: Exception) -> ForecastBet:
    log.warning(
        "forecast_live_bet_exchange_error",
        bet_id=bet_id,
        error_code=type(exc).__name__,
        error_message=str(exc),
    )
    with store.session() as session:
        bet = session.get(ForecastBet, bet_id)
        if bet is None:
            raise KeyError(f"unknown forecast bet: {bet_id}") from exc
        bet.status = ForecastBetStatus.FAILED
        session.add(bet)
        session.commit()
        session.refresh(bet)
        return bet.model_copy()


def _portfolio_state_or_none(
    session: Any,
    organization_id: str,
) -> ForecastPortfolioState | None:
    from sqlmodel import select

    return session.exec(
        select(ForecastPortfolioState).where(
            ForecastPortfolioState.organization_id == organization_id
        )
    ).first()


def _portfolio_state(
    session: Any,
    organization_id: str,
    *,
    now: datetime,
) -> ForecastPortfolioState:
    state = _portfolio_state_or_none(session, organization_id)
    if state is not None:
        return state
    state = ForecastPortfolioState(
        organization_id=organization_id,
        paper_balance_usd=Decimal("0.00"),
        live_balance_usd=Decimal("0.00"),
        daily_loss_usd=Decimal("0.00"),
        daily_loss_reset_at=now,
        kill_switch_engaged=False,
        kill_switch_reason=None,
        updated_at=now,
    )
    session.add(state)
    session.flush()
    return state


def _bet_status_from_order(order: Any) -> ForecastBetStatus:
    status = str(getattr(order, "status", "")).strip().upper()
    if status in {"FILLED", "EXECUTED", "MATCHED"}:
        return ForecastBetStatus.FILLED
    if status in {"CANCELLED", "CANCELED", "CANCEL"}:
        return ForecastBetStatus.CANCELLED
    if status in {"FAILED", "FAIL", "REJECTED", "ERROR"}:
        return ForecastBetStatus.FAILED
    return ForecastBetStatus.SUBMITTED


def _is_partial_fill(order: Any, expected_fill: Decimal) -> bool:
    filled = _decimal(getattr(order, "filled_size", Decimal("0")))
    return Decimal("0") < filled < expected_fill


def _settlement_payoff(
    bet: ForecastBet,
    outcome: ForecastOutcome,
) -> tuple[Decimal, Decimal]:
    if outcome == ForecastOutcome.CANCELLED:
        return _money(Decimal(bet.stake_usd)), _price(Decimal(bet.entry_price))
    side_won = (
        (outcome == ForecastOutcome.YES and _enum_value(bet.side) == "YES")
        or (outcome == ForecastOutcome.NO and _enum_value(bet.side) == "NO")
    )
    if not side_won:
        return Decimal("0.00"), Decimal("0.000000")
    return (
        _money(Decimal(bet.stake_usd) / Decimal(bet.entry_price)),
        Decimal("1.000000"),
    )


def _polymarket_token_id(
    market: ForecastMarket,
    side: ForecastBetSide,
) -> tuple[str, int]:
    outcome_index = 0 if side == ForecastBetSide.YES else 1
    token_ids = _payload_array(
        market.raw_payload.get("clobTokenIds")
        or market.raw_payload.get("clob_token_ids")
        or market.raw_payload.get("tokenIds")
        or market.raw_payload.get("token_ids")
    )
    outcomes = [_outcome_label(item).lower() for item in _payload_array(
        market.raw_payload.get("outcomes") or market.raw_payload.get("outcome")
    )]
    if outcomes:
        try:
            outcome_index = outcomes.index(side.value.lower())
        except ValueError:
            pass
    if token_ids and outcome_index < len(token_ids):
        return str(token_ids[outcome_index]), outcome_index
    return market.external_id, outcome_index


def _payload_array(value: Any) -> list[Any]:
    if value is None:
        return []
    if isinstance(value, list):
        return value
    if isinstance(value, tuple):
        return list(value)
    if isinstance(value, str):
        stripped = value.strip()
        if not stripped:
            return []
        if stripped.startswith("["):
            import json

            parsed = json.loads(stripped)
            return parsed if isinstance(parsed, list) else []
        return [stripped]
    return []


def _outcome_label(value: Any) -> str:
    if isinstance(value, dict):
        return str(
            value.get("name")
            or value.get("label")
            or value.get("outcome")
            or ""
        )
    return str(value)


def _poll_timeout_s() -> float:
    raw = os.getenv("FORECASTS_LIVE_ORDER_POLL_TIMEOUT_S", "30")
    return max(0.0, float(raw))


def _decimal(value: Any) -> Decimal:
    try:
        return Decimal(str(value))
    except (InvalidOperation, ValueError, TypeError) as exc:
        raise ValueError(f"not a decimal value: {value!r}") from exc


def _money(value: Decimal) -> Decimal:
    return Decimal(value).quantize(MONEY, rounding=ROUND_HALF_UP)


def _price(value: Decimal) -> Decimal:
    return Decimal(value).quantize(PRICE, rounding=ROUND_HALF_UP)


def _enum_value(value: Any) -> str:
    return str(value.value if hasattr(value, "value") else value)

"""Live Polymarket CLOB adapter for Forecasts.

The Polymarket CLOB currently signs orders as EIP-712 payloads and uses L2
HMAC credentials for authenticated trading requests. This wrapper intentionally
delegates those moving parts to Polymarket's SDK when live trading is actually
enabled; importing this module never constructs a wallet or contacts the CLOB.
"""

from __future__ import annotations

import asyncio
import os
from decimal import Decimal, InvalidOperation
from typing import Any, Literal

from pydantic import BaseModel, Field

from noosphere.forecasts._polymarket_client import PolymarketGammaClient


class PolymarketLiveOrder(BaseModel):
    external_order_id: str
    status: str
    filled_size: Decimal = Decimal("0")
    average_price: Decimal | None = None
    raw_payload: dict[str, Any] = Field(default_factory=dict)


class PolymarketLiveClient(PolymarketGammaClient):
    """Async live-trading facade over the Polymarket CLOB SDK."""

    def __init__(
        self,
        *,
        base: str = "https://clob.polymarket.com",
        private_key: str | None = None,
        chain_id: int = 137,
        signature_type: int = 0,
        funder: str | None = None,
        tick_size: str = "0.01",
        neg_risk: bool = False,
        timeout_s: float = 15.0,
    ) -> None:
        super().__init__(base=base, timeout_s=timeout_s)
        self._private_key = (
            private_key or os.getenv("POLYMARKET_PRIVATE_KEY", "")
        ).strip()
        self._chain_id = chain_id
        self._signature_type = signature_type
        self._funder = funder
        self._tick_size = tick_size
        self._neg_risk = neg_risk
        self._sdk_client: Any | None = None
        self.wallet_address = _wallet_address_or_none(self._private_key)

    @classmethod
    def from_env(cls) -> PolymarketLiveClient:
        return cls(
            base=os.getenv("POLYMARKET_CLOB_BASE", "https://clob.polymarket.com"),
            private_key=os.getenv("POLYMARKET_PRIVATE_KEY", ""),
            chain_id=int(os.getenv("POLYMARKET_CHAIN_ID", "137")),
            signature_type=int(os.getenv("POLYMARKET_SIGNATURE_TYPE", "0")),
            funder=os.getenv("POLYMARKET_FUNDER_ADDRESS", "").strip() or None,
            tick_size=os.getenv("POLYMARKET_DEFAULT_TICK_SIZE", "0.01"),
            neg_risk=os.getenv("POLYMARKET_DEFAULT_NEG_RISK", "").strip().lower()
            in {"1", "true", "yes", "y"},
        )

    async def place_order(
        self,
        condition_id: str,
        outcome_index: int,
        side: Literal["BUY", "SELL"],
        size: Decimal | float | str,
        price: Decimal | float | str,
        order_type: str,
    ) -> PolymarketLiveOrder:
        """Create, EIP-712 sign, and post an order through the CLOB SDK.

        Polymarket's current docs describe `createAndPostOrder` /
        `createOrder` + `postOrder` over `tokenID`. The local market mirror
        stores `conditionId`; callers should pass the resolved CLOB token id
        when it is available and fall back to the condition id only for mocks.
        """

        payload = await asyncio.to_thread(
            self._sdk_place_order,
            condition_id,
            outcome_index,
            side,
            size,
            price,
            order_type,
        )
        return _order_from_payload(payload)

    async def cancel_order(self, order_id: str) -> PolymarketLiveOrder:
        payload = await asyncio.to_thread(self._sdk_cancel_order, order_id)
        return _order_from_payload(
            payload,
            fallback_order_id=order_id,
            fallback_status="CANCELLED",
        )

    async def get_order(self, order_id: str) -> PolymarketLiveOrder:
        payload = await asyncio.to_thread(self._sdk_get_order, order_id)
        return _order_from_payload(payload, fallback_order_id=order_id)

    def _sdk_place_order(
        self,
        token_id: str,
        _outcome_index: int,
        side: str,
        size: Decimal | float | str,
        price: Decimal | float | str,
        order_type: str,
    ) -> dict[str, Any]:
        client = self._ensure_sdk_client()
        sdk_side = _sdk_side(side)
        sdk_order_type = _sdk_order_type(order_type)
        order_args = _sdk_order_args(
            token_id=token_id,
            price=float(_decimal(price)),
            size=float(_decimal(size)),
            side=sdk_side,
        )
        options = {"tickSize": self._tick_size, "negRisk": self._neg_risk}

        method = getattr(client, "createAndPostOrder", None) or getattr(
            client,
            "create_and_post_order",
            None,
        )
        if method is not None:
            return _payload_dict(method(order_args, options, sdk_order_type))

        create_order = getattr(client, "createOrder", None) or getattr(
            client,
            "create_order",
            None,
        )
        post_order = getattr(client, "postOrder", None) or getattr(
            client,
            "post_order",
            None,
        )
        if create_order is None or post_order is None:
            raise RuntimeError(
                "Polymarket SDK does not expose create/post order methods expected "
                "by the CLOB docs"
            )
        signed_order = create_order(order_args, options)
        return _payload_dict(post_order(signed_order, sdk_order_type))

    def _sdk_cancel_order(self, order_id: str) -> dict[str, Any]:
        client = self._ensure_sdk_client()
        method = getattr(client, "cancelOrder", None) or getattr(client, "cancel", None)
        if method is None:
            raise RuntimeError("Polymarket SDK does not expose cancelOrder/cancel")
        return _payload_dict(method(order_id))

    def _sdk_get_order(self, order_id: str) -> dict[str, Any]:
        client = self._ensure_sdk_client()
        method = getattr(client, "getOrder", None) or getattr(client, "get_order", None)
        if method is None:
            raise RuntimeError("Polymarket SDK does not expose getOrder/get_order")
        return _payload_dict(method(order_id))

    def _ensure_sdk_client(self) -> Any:
        if not self._private_key:
            raise RuntimeError("POLYMARKET_PRIVATE_KEY is required for live trading")
        if self._sdk_client is not None:
            return self._sdk_client

        try:
            from py_clob_client.client import ClobClient
        except ImportError as exc:  # pragma: no cover - depends on optional live SDK.
            raise RuntimeError(
                "py-clob-client is required for Polymarket live trading"
            ) from exc

        kwargs: dict[str, Any] = {
            "host": self._base,
            "key": self._private_key,
            "chain_id": self._chain_id,
        }
        if self._signature_type is not None:
            kwargs["signature_type"] = self._signature_type
        if self._funder:
            kwargs["funder"] = self._funder
        client = ClobClient(**kwargs)

        derive = getattr(client, "create_or_derive_api_creds", None) or getattr(
            client,
            "createOrDeriveApiKey",
            None,
        )
        set_creds = getattr(client, "set_api_creds", None) or getattr(
            client,
            "setApiCreds",
            None,
        )
        if derive is not None and set_creds is not None:
            set_creds(derive())

        self._sdk_client = client
        return client


def _wallet_address_or_none(private_key: str) -> str | None:
    if not private_key:
        return None
    try:
        from eth_account import Account
    except ImportError:  # pragma: no cover - optional live dependency.
        return None
    return str(Account.from_key(private_key).address)


def _sdk_order_args(*, token_id: str, price: float, size: float, side: Any) -> Any:
    try:
        from py_clob_client.clob_types import OrderArgs
    except ImportError:  # pragma: no cover - handled before live use.
        return {
            "tokenID": token_id,
            "token_id": token_id,
            "price": price,
            "size": size,
            "side": side,
        }
    try:
        return OrderArgs(price=price, size=size, side=side, token_id=token_id)
    except TypeError:
        return OrderArgs(price=price, size=size, side=side, tokenID=token_id)


def _sdk_side(side: str) -> Any:
    normalized = side.upper()
    try:
        from py_clob_client.order_builder.constants import BUY, SELL

        return BUY if normalized == "BUY" else SELL
    except ImportError:  # pragma: no cover - handled before live use.
        return normalized


def _sdk_order_type(order_type: str) -> Any:
    normalized = order_type.upper()
    try:
        from py_clob_client.clob_types import OrderType
    except ImportError:  # pragma: no cover - handled before live use.
        return normalized
    return getattr(OrderType, normalized, normalized)


def _order_from_payload(
    payload: dict[str, Any],
    *,
    fallback_order_id: str | None = None,
    fallback_status: str | None = None,
) -> PolymarketLiveOrder:
    order_id = _str_first(
        payload,
        "external_order_id",
        "orderID",
        "order_id",
        "id",
    ) or fallback_order_id
    if not order_id:
        raise RuntimeError("Polymarket order response missing order id")
    status = _str_first(payload, "status", "state") or fallback_status or "SUBMITTED"
    return PolymarketLiveOrder(
        external_order_id=order_id,
        status=str(status),
        filled_size=_decimal_first(
            payload,
            "filled_size",
            "filledSize",
            "filledAmount",
            "filled_amount",
            "matchedAmount",
        ),
        average_price=_decimal_first_or_none(
            payload,
            "average_price",
            "averagePrice",
            "avgPrice",
            "price",
        ),
        raw_payload=payload,
    )


def _payload_dict(value: Any) -> dict[str, Any]:
    if isinstance(value, dict):
        return value
    if hasattr(value, "model_dump"):
        dumped = value.model_dump()
        return dumped if isinstance(dumped, dict) else {"value": dumped}
    if hasattr(value, "dict"):
        dumped = value.dict()
        return dumped if isinstance(dumped, dict) else {"value": dumped}
    if hasattr(value, "__dict__"):
        return dict(value.__dict__)
    raise RuntimeError(
        f"unexpected Polymarket SDK payload type: {type(value).__name__}"
    )


def _str_first(payload: dict[str, Any], *keys: str) -> str | None:
    for key in keys:
        value = payload.get(key)
        if value is not None and str(value).strip():
            return str(value).strip()
    return None


def _decimal_first(payload: dict[str, Any], *keys: str) -> Decimal:
    return _decimal_first_or_none(payload, *keys) or Decimal("0")


def _decimal_first_or_none(payload: dict[str, Any], *keys: str) -> Decimal | None:
    for key in keys:
        value = payload.get(key)
        if value is None:
            continue
        try:
            return _decimal(value)
        except ValueError:
            continue
    return None


def _decimal(value: Any) -> Decimal:
    try:
        return Decimal(str(value))
    except (InvalidOperation, ValueError, TypeError) as exc:
        raise ValueError(f"not a decimal value: {value!r}") from exc

"""Live Kalshi order adapter for Forecasts."""

from __future__ import annotations

import json
import os
from dataclasses import dataclass, field
from decimal import ROUND_HALF_UP, Decimal, InvalidOperation
from typing import Any, Literal

from noosphere.forecasts._kalshi_client import KalshiAPIError, KalshiClient


@dataclass(frozen=True)
class KalshiLiveOrder:
    external_order_id: str
    status: str
    filled_size: Decimal = Decimal("0")
    average_price: Decimal | None = None
    raw_payload: dict[str, Any] = field(default_factory=dict)


class KalshiLiveClient(KalshiClient):
    @classmethod
    def from_env(cls) -> KalshiLiveClient:
        private_key = (
            os.getenv("KALSHI_API_PRIVATE_KEY", "").replace("\\n", "\n").strip()
            or os.getenv("KALSHI_PRIVATE_KEY_PEM", "").replace("\\n", "\n").strip()
        )
        return cls(
            base=os.getenv(
                "KALSHI_API_BASE",
                "https://api.elections.kalshi.com/trade-api/v2",
            ),
            key_id=os.getenv("KALSHI_API_KEY_ID", "").strip(),
            private_key_pem=private_key,
        )

    async def place_order(
        self,
        ticker: str,
        side: Literal["YES", "NO", "yes", "no"],
        count: int,
        price: Decimal | float | str,
        order_type: str,
        client_order_id: str,
    ) -> KalshiLiveOrder:
        side_value = side.lower()
        if side_value not in {"yes", "no"}:
            raise ValueError("Kalshi side must be yes or no")
        body: dict[str, Any] = {
            "ticker": ticker,
            "side": side_value,
            "action": "buy",
            "client_order_id": client_order_id,
            "count": int(count),
            f"{side_value}_price": _price_cents(price),
            "time_in_force": _time_in_force(order_type),
        }
        payload = await self._request_json("POST", "/portfolio/orders", json_body=body)
        return _order_from_payload(payload)

    async def cancel_order(self, order_id: str) -> KalshiLiveOrder:
        payload = await self._request_json("DELETE", f"/portfolio/orders/{order_id}")
        return _order_from_payload(
            payload,
            fallback_order_id=order_id,
            fallback_status="CANCELLED",
        )

    async def get_order(self, order_id: str) -> KalshiLiveOrder:
        payload = await self._request_json("GET", f"/portfolio/orders/{order_id}")
        return _order_from_payload(payload, fallback_order_id=order_id)

    async def _request_json(
        self,
        method: str,
        path: str,
        *,
        json_body: dict[str, Any] | None = None,
    ) -> Any:
        client = self._ensure_client()
        headers = self._signed_headers(method, path)
        headers["Content-Type"] = "application/json"
        content = (
            json.dumps(json_body).encode("utf-8")
            if json_body is not None
            else None
        )
        response = await client.request(
            method,
            f"{self._base}{path}",
            headers=headers,
            content=content,
        )
        if response.status_code == 404:
            raise KalshiAPIError(404, response.text)
        if 400 <= response.status_code:
            raise KalshiAPIError(response.status_code, response.text)
        if not response.content:
            return {}
        return response.json()


def _order_from_payload(
    payload: Any,
    *,
    fallback_order_id: str | None = None,
    fallback_status: str | None = None,
) -> KalshiLiveOrder:
    if not isinstance(payload, dict):
        raise RuntimeError("unexpected Kalshi order payload shape")
    order = payload.get("order")
    if isinstance(order, dict):
        payload = order
    order_id = (
        _str_first(payload, "external_order_id", "order_id", "id")
        or fallback_order_id
    )
    if not order_id:
        raise RuntimeError("Kalshi order response missing order_id")
    status = _str_first(payload, "status", "state") or fallback_status or "SUBMITTED"
    filled_size = _decimal_first(
        payload,
        "filled_size",
        "filledSize",
        "fill_count_fp",
        "filled_count",
    )
    return KalshiLiveOrder(
        external_order_id=order_id,
        status=str(status),
        filled_size=filled_size,
        average_price=_average_price(payload, filled_size),
        raw_payload=payload,
    )


def _average_price(payload: dict[str, Any], filled_size: Decimal) -> Decimal | None:
    for key in (
        "average_price",
        "averagePrice",
        "yes_price_dollars",
        "no_price_dollars",
    ):
        value = payload.get(key)
        if value is not None:
            try:
                return _decimal(value)
            except ValueError:
                continue
    cost = _decimal_first_or_none(
        payload,
        "taker_fill_cost_dollars",
        "maker_fill_cost_dollars",
    )
    if cost is None or filled_size <= Decimal("0"):
        return None
    return (cost / filled_size).quantize(Decimal("0.000001"), rounding=ROUND_HALF_UP)


def _time_in_force(order_type: str) -> str:
    normalized = order_type.strip().upper()
    return {
        "FOK": "fill_or_kill",
        "FAK": "immediate_or_cancel",
        "IOC": "immediate_or_cancel",
        "GTC": "good_till_canceled",
        "GOOD_TILL_CANCELED": "good_till_canceled",
    }.get(normalized, order_type.strip().lower())


def _price_cents(value: Decimal | float | str) -> int:
    cents = (_decimal(value) * Decimal("100")).quantize(
        Decimal("1"),
        rounding=ROUND_HALF_UP,
    )
    if not Decimal("1") <= cents <= Decimal("99"):
        raise ValueError("Kalshi order price must be between 0.01 and 0.99")
    return int(cents)


def _str_first(payload: dict[str, Any], *keys: str) -> str | None:
    for key in keys:
        value = payload.get(key)
        if value is not None and str(value).strip():
            return str(value).strip()
    return None


def _decimal_first(payload: dict[str, Any], *keys: str) -> Decimal:
    return _decimal_first_or_none(payload, *keys) or Decimal("0")


def _decimal_first_or_none(payload: dict[str, Any], *keys: str) -> Decimal | None:
    for key in keys:
        value = payload.get(key)
        if value is None:
            continue
        try:
            return _decimal(value)
        except ValueError:
            continue
    return None


def _decimal(value: Any) -> Decimal:
    try:
        return Decimal(str(value))
    except (InvalidOperation, ValueError, TypeError) as exc:
        raise ValueError(f"not a decimal value: {value!r}") from exc

